+} = require("./moderation.service");
+const { flagSharedDeviceRisk, handleUpheldViolation, refreshGovernanceAnalyticsSnapshot } = require("./risk.service");
+const { canCreateFollowup, canAppeal } = require("./review.rules");
+
+async function createReview({ userId, payload, requestId }) {
+  await ensureUserNotBlacklisted(userId);
+  await enforceDailyPublishCap(userId);
+  await checkSensitiveWords(payload.reviewText);
+
+  const connection = await pool.getConnection();
+  try {
+    await connection.beginTransaction();
+
+    const [orderRows] = await connection.query(
+      `
+        SELECT id, order_status
+        FROM orders
+        WHERE id = ? AND user_id = ?
+        LIMIT 1
+        FOR UPDATE
+      `,
+      [payload.orderId, userId]
+    );
+
+    if (!orderRows.length) {
+      throw new ApiError(404, "ORDER_NOT_FOUND", "Order not found for user");
+    }
+    if (orderRows[0].order_status !== "completed") {
+      throw new ApiError(400, "ORDER_NOT_COMPLETED", "Only completed orders can be reviewed");
+    }
+
+    const [existingRows] = await connection.query("SELECT id FROM reviews WHERE order_id = ? AND user_id = ? LIMIT 1", [
+      payload.orderId,
+      userId
+    ]);
+    if (existingRows.length) {
+      throw new ApiError(409, "REVIEW_ALREADY_EXISTS", "One primary review per order is allowed");
+    }
+
+    const [insert] = await connection.query(
+      `
+        INSERT INTO reviews (order_id, user_id, rating, review_state, anonymous_display, review_text, published_at)
+        VALUES (?, ?, ?, 'published', ?, ?, CURRENT_TIMESTAMP)
+      `,
+      [payload.orderId, userId, payload.rating, payload.anonymousDisplay ? 1 : 0, payload.reviewText]
+    );
+
+    for (const dimension of payload.dimensionScores) {
+      const [dimensionRows] = await connection.query("SELECT id FROM review_dimension_configs WHERE id = ? AND is_active = 1 LIMIT 1", [
+        dimension.dimensionConfigId
+      ]);
+      if (!dimensionRows.length) {
+        throw new ApiError(400, "INVALID_DIMENSION", `Dimension ${dimension.dimensionConfigId} is not active`);
+      }
+
+      await connection.query(
+        `
+          INSERT INTO review_dimension_scores (review_id, dimension_config_id, score)
+          VALUES (?, ?, ?)
+        `,
+        [insert.insertId, dimension.dimensionConfigId, dimension.score]
+      );
+    }
+
+    await connection.query(
+      `
+        INSERT INTO moderation_events (review_id, actor_user_id, event_type, decision, notes)
+        VALUES (?, ?, 'review_publish', 'allow', 'Passed baseline moderation checks')
+      `,
+      [insert.insertId, userId]
+    );
+
+    await connection.commit();
+
+    await flagSharedDeviceRisk(userId);
+    await refreshGovernanceAnalyticsSnapshot();
+    await writeAuditEvent({
+      actorUserId: userId,
+      eventType: "review.created",
+      entityType: "review",
+      entityId: String(insert.insertId),
+      requestId,
+      payload: { orderId: payload.orderId }
+    });
+
+    const [rows] = await pool.query("SELECT * FROM reviews WHERE id = ? LIMIT 1", [insert.insertId]);
+    return rows[0];
+  } catch (error) {
+    await connection.rollback();
+    throw error;
+  } finally {
+    connection.release();
+  }
+}
+
+async function addFollowup({ userId, reviewId, followupText, requestId }) {
+  await ensureUserNotBlacklisted(userId);
+  await enforceDailyPublishCap(userId);
+  await checkSensitiveWords(followupText);
+
+  const connection = await pool.getConnection();
+  try {
+    await connection.beginTransaction();
+
+    const [reviewRows] = await connection.query("SELECT * FROM reviews WHERE id = ? AND user_id = ? LIMIT 1 FOR UPDATE", [reviewId, userId]);
+    if (!reviewRows.length) {
+      throw new ApiError(404, "REVIEW_NOT_FOUND", "Review not found for user");
+    }
+
+    const review = reviewRows[0];
+    if (!canCreateFollowup(review.published_at)) {
+      throw new ApiError(400, "FOLLOWUP_WINDOW_EXPIRED", "Follow-up review is only allowed within 30 days");
+    }
+
+    const [existingRows] = await connection.query("SELECT id FROM review_followups WHERE review_id = ? LIMIT 1", [reviewId]);
+    if (existingRows.length) {
+      throw new ApiError(409, "FOLLOWUP_ALREADY_EXISTS", "Only one follow-up review is allowed");
+    }
+
+    const [insert] = await connection.query(
+      `
+        INSERT INTO review_followups (review_id, user_id, followup_text)
+        VALUES (?, ?, ?)
+      `,
+      [reviewId, userId, followupText]
+    );
+
+    await connection.commit();
+
+    await writeAuditEvent({
+      actorUserId: userId,
+      eventType: "review.followup.created",
+      entityType: "review_followup",
+      entityId: String(insert.insertId),
+      requestId,
+      payload: { reviewId }
+    });
+
+    const [rows] = await pool.query("SELECT * FROM review_followups WHERE id = ? LIMIT 1", [insert.insertId]);
+    return rows[0];
+  } catch (error) {
+    await connection.rollback();
+    throw error;
+  } finally {
+    connection.release();
+  }
+}
+
+async function getReviewDetail({ reviewId, requester }) {
+  const [reviewRows] = await pool.query(
+    `
+      SELECT r.*, u.username, p.display_name
+      FROM reviews r
+      JOIN users u ON u.id = r.user_id
+      LEFT JOIN user_profiles p ON p.user_id = r.user_id
+      WHERE r.id = ?
+      LIMIT 1
+    `,
+    [reviewId]
+  );
+  if (!reviewRows.length) {
+    throw new ApiError(404, "REVIEW_NOT_FOUND", "Review not found");
+  }
+
+  const review = reviewRows[0];
+  const hidden = review.review_state === "under_arbitration";
+  const displayName = review.anonymous_display ? "Anonymous User" : review.display_name || review.username;
+
+  const [dimensionRows] = await pool.query(
+    `
+      SELECT ds.dimension_config_id, ds.score, dc.label, dc.key_name
+      FROM review_dimension_scores ds
+      JOIN review_dimension_configs dc ON dc.id = ds.dimension_config_id
+      WHERE ds.review_id = ?
+    `,
+    [reviewId]
+  );
+
+  const [imageRows] = await pool.query(
+    "SELECT id, mime_type, file_size_bytes, sort_order FROM review_images WHERE review_id = ? ORDER BY sort_order ASC, id ASC",
+    [reviewId]
+  );
+
+  const [followupRows] = await pool.query("SELECT * FROM review_followups WHERE review_id = ? LIMIT 1", [reviewId]);
+  const [replyRows] = await pool.query(
+    `
+      SELECT rr.id, rr.parent_reply_id, rr.reply_text, rr.created_at, rr.author_role, u.username
+      FROM review_replies rr
+      JOIN users u ON u.id = rr.author_user_id
+      WHERE rr.review_id = ?
+      ORDER BY rr.id ASC
+    `,
+    [reviewId]
+  );
+  const [appealRows] = await pool.query("SELECT * FROM appeals WHERE review_id = ? ORDER BY id DESC", [reviewId]);
+  const appeal = appealRows[0] || null;
+
+  let timeline = [];
+  if (appeal) {
+    const [timelineRows] = await pool.query(
+      "SELECT event_type, event_status, event_note, created_at FROM appeal_timeline_events WHERE appeal_id = ? ORDER BY id ASC",
+      [appeal.id]
+    );
+    timeline = timelineRows;
+  }
+
+  const canAppealNow = requester && requester.id === review.user_id && canAppeal(review.published_at) && (!appeal || appeal.appeal_status === "resolved");
+
+  return {
+    id: review.id,
+    orderId: review.order_id,
+    userId: review.user_id,
+    rating: review.rating,
+    reviewState: review.review_state,
+    displayName,
+    anonymousDisplay: Boolean(review.anonymous_display),
+    reviewText: hidden ? "Content hidden during arbitration" : review.review_text,
+    publishedAt: review.published_at,
+    dimensions: dimensionRows,
+    images: hidden ? [] : imageRows,
+    followup: hidden ? null : followupRows[0] || null,
+    replies: replyRows,
+    appeal: appeal
+      ? {
+          id: appeal.id,
+          status: appeal.appeal_status,
+          submittedAt: appeal.submitted_at,
+          resolvedAt: appeal.resolved_at,
+          timeline
+        }
+      : null,
+    canAppeal: Boolean(canAppealNow)
+  };
+}
+
+async function createAppeal({ userId, reviewId, reason, requestId }) {
+  const connection = await pool.getConnection();
+  try {
+    await connection.beginTransaction();
+
+    const [reviewRows] = await connection.query("SELECT * FROM reviews WHERE id = ? AND user_id = ? LIMIT 1 FOR UPDATE", [reviewId, userId]);
+    if (!reviewRows.length) {
+      throw new ApiError(404, "REVIEW_NOT_FOUND", "Review not found for user");
+    }
+
+    const review = reviewRows[0];
+    if (!canAppeal(review.published_at)) {
+      throw new ApiError(400, "APPEAL_WINDOW_EXPIRED", "Appeals can be submitted within 7 days of publishing");
+    }
+
+    const [existingAppealRows] = await connection.query(
+      "SELECT id FROM appeals WHERE review_id = ? AND appeal_status IN ('submitted', 'under_review') LIMIT 1",
+      [reviewId]
+    );
+    if (existingAppealRows.length) {
+      throw new ApiError(409, "APPEAL_ALREADY_OPEN", "An appeal is already active for this review");
+    }
+
+    const [insert] = await connection.query(
+      `
+        INSERT INTO appeals (review_id, appellant_user_id, appeal_status, appeal_reason)
+        VALUES (?, ?, 'submitted', ?)
+      `,
+      [reviewId, userId, reason]
+    );
+
+    await connection.query(
+      `
+        INSERT INTO appeal_timeline_events (appeal_id, event_type, event_status, event_note, created_by_user_id)
+        VALUES (?, 'appeal_submitted', 'submitted', ?, ?)
+      `,
+      [insert.insertId, "Appeal submitted", userId]
+    );
+
+    await connection.query("UPDATE reviews SET review_state = 'under_arbitration' WHERE id = ?", [reviewId]);
+    await connection.commit();
+
+    await writeAuditEvent({
+      actorUserId: userId,
+      eventType: "appeal.created",
+      entityType: "appeal",
+      entityId: String(insert.insertId),
+      requestId,
+      payload: { reviewId }
+    });
+
+    const [rows] = await pool.query("SELECT * FROM appeals WHERE id = ? LIMIT 1", [insert.insertId]);
+    return rows[0];
+  } catch (error) {
+    await connection.rollback();
+    throw error;
+  } finally {
+    connection.release();
+  }
+}
+
+async function addReply({ actorUser, reviewId, parentReplyId, replyText, requestId }) {
+  await checkSensitiveWords(replyText);
+
+  const [reviewRows] = await pool.query("SELECT id FROM reviews WHERE id = ? LIMIT 1", [reviewId]);
+  if (!reviewRows.length) {
+    throw new ApiError(404, "REVIEW_NOT_FOUND", "Review not found");
+  }
+
+  if (parentReplyId) {
+    const [parentRows] = await pool.query("SELECT id FROM review_replies WHERE id = ? AND review_id = ? LIMIT 1", [parentReplyId, reviewId]);
+    if (!parentRows.length) {
+      throw new ApiError(400, "INVALID_PARENT_REPLY", "Parent reply does not belong to this review");
+    }
+  }
+
+  const role = actorUser.roles.includes("coach")
+    ? "coach"
+    : actorUser.roles.includes("support")
+      ? "support"
+      : actorUser.roles.includes("admin")
+        ? "admin"
+        : "user";
+
+  const [insert] = await pool.query(
+    `
+      INSERT INTO review_replies (review_id, parent_reply_id, author_user_id, author_role, reply_text)
+      VALUES (?, ?, ?, ?, ?)
+    `,
+    [reviewId, parentReplyId || null, actorUser.id, role, replyText]
+  );
+
+  await writeAuditEvent({
+    actorUserId: actorUser.id,
+    eventType: "review.reply.created",
+    entityType: "review_reply",
+    entityId: String(insert.insertId),
+    requestId,
+    payload: { reviewId }
+  });
+
+  const [rows] = await pool.query("SELECT * FROM review_replies WHERE id = ? LIMIT 1", [insert.insertId]);
+  return rows[0];
+}
+
+async function listUserReviews(userId) {
+  const [rows] = await pool.query(
+    `
+      SELECT r.id, r.order_id, r.rating, r.review_state, r.anonymous_display, r.review_text, r.published_at, r.created_at,
+             o.order_status
+      FROM reviews r
+      JOIN orders o ON o.id = r.order_id
+      WHERE r.user_id = ?
+      ORDER BY r.id DESC
+    `,
+    [userId]
+  );
+
+  if (!rows.length) {
+    return [];
+  }
+
+  const reviewIds = rows.map((row) => row.id);
+  const [imageRows] = await pool.query(
+    `
+      SELECT review_id, id, mime_type, sort_order
+      FROM review_images
+      WHERE review_id IN (?)
+      ORDER BY review_id ASC, sort_order ASC, id ASC
+    `,
+    [reviewIds]
+  );
+
+  const [followupRows] = await pool.query(
+    `
+      SELECT id, review_id, followup_text, created_at
+      FROM review_followups
+      WHERE review_id IN (?)
+    `,
+    [reviewIds]
+  );
+
+  const imagesByReview = new Map();
+  for (const image of imageRows) {
+    if (!imagesByReview.has(image.review_id)) {
+      imagesByReview.set(image.review_id, []);
+    }
+    imagesByReview.get(image.review_id).push({
+      id: image.id,
+      mimeType: image.mime_type,
+      url: `/api/v1/reviews/images/${image.id}`
+    });
+  }
+
+  const followupByReview = new Map();
+  for (const followup of followupRows) {
+    followupByReview.set(followup.review_id, {
+      id: followup.id,
+      followupText: followup.followup_text,
+      createdAt: followup.created_at
+    });
+  }
+
+  return rows.map((row) => {
+    const hidden = row.review_state === "under_arbitration";
+    const images = hidden ? [] : imagesByReview.get(row.id) || [];
+    return {
+      ...row,
+      image_count: images.length,
+      image_previews: images.slice(0, 3),
+      followup: hidden ? null : followupByReview.get(row.id) || null
+    };
+  });
+}
+
+async function listAppealsForStaff(status = null) {
+  const [rows] = await pool.query(
+    `
+      SELECT a.*, r.user_id AS review_author_user_id, r.review_state, r.review_text
+      FROM appeals a
+      JOIN reviews r ON r.id = a.review_id
+      ${status ? "WHERE a.appeal_status = ?" : ""}
+      ORDER BY a.id DESC
+      LIMIT 500
+    `,
+    status ? [status] : []
+  );
+
+  return rows;
+}
+
+async function updateAppealStatus({ actorUserId, appealId, appealStatus, note, requestId }) {
+  const connection = await pool.getConnection();
+  try {
+    await connection.beginTransaction();
+
+    const [appealRows] = await connection.query("SELECT * FROM appeals WHERE id = ? LIMIT 1 FOR UPDATE", [appealId]);
+    if (!appealRows.length) {
+      throw new ApiError(404, "APPEAL_NOT_FOUND", "Appeal not found");
+    }
+
+    const appeal = appealRows[0];
+    await connection.query(
+      "UPDATE appeals SET appeal_status = ?, resolved_at = CASE WHEN ? IN ('upheld','rejected','resolved') THEN CURRENT_TIMESTAMP ELSE resolved_at END WHERE id = ?",
+      [appealStatus, appealStatus, appealId]
+    );
+
+    await connection.query(
+      `
+        INSERT INTO appeal_timeline_events (appeal_id, event_type, event_status, event_note, created_by_user_id)
+        VALUES (?, 'status_update', ?, ?, ?)
+      `,
+      [appealId, appealStatus, note || null, actorUserId]
+    );
+
+    if (appealStatus === "under_review") {
+      await connection.query("UPDATE reviews SET review_state = 'under_arbitration' WHERE id = ?", [appeal.review_id]);
+    } else if (appealStatus === "upheld") {
+      await connection.query("UPDATE reviews SET review_state = 'hidden' WHERE id = ?", [appeal.review_id]);
+    } else {
+      await connection.query("UPDATE reviews SET review_state = 'published' WHERE id = ?", [appeal.review_id]);
+    }
+
+    await connection.commit();
+
+    if (appealStatus === "upheld") {
+      const [reviewRows] = await pool.query("SELECT user_id FROM reviews WHERE id = ? LIMIT 1", [appeal.review_id]);
+      if (reviewRows.length) {
+        await handleUpheldViolation(reviewRows[0].user_id);
+      }
+    }
+
+    await refreshGovernanceAnalyticsSnapshot();
+    await writeAuditEvent({
+      actorUserId,
+      eventType: "appeal.status.updated",
+      entityType: "appeal",
+      entityId: String(appealId),
+      requestId,
+      payload: { appealStatus }
+    });
+
+    const [rows] = await pool.query("SELECT * FROM appeals WHERE id = ? LIMIT 1", [appealId]);
+    return rows[0];
+  } catch (error) {
+    await connection.rollback();
+    throw error;
+  } finally {
+    connection.release();
+  }
+}
+
+module.exports = {
+  createReview,
+  addFollowup,
+  listUserReviews,
+  listAppealsForStaff,
+  getReviewDetail,
+  createAppeal,
+  addReply,
+  updateAppealStatus
+};

