const ROOT_DIR = path.resolve(__dirname, "..");
const SUMMARY_FILE = path.join(__dirname, ".summary");

function setModuleMock(modulePath, exportsObj) {
  require.cache[modulePath] = {
    id: modulePath,
    filename: modulePath,
    loaded: true,
    exports: exportsObj
  };
}

function clearModule(modulePath) {
  delete require.cache[modulePath];
}

function assert(condition, message, context = null) {
  if (!condition) {
    const error = new Error(message);
    error.context = context;
    throw error;
  }
}

function failureSnippet(error) {
  if (error.context) {
    return JSON.stringify(error.context).slice(0, 400);
  }
  if (error.stack) {
    return error.stack.split("\n").slice(0, 3).join(" | ");
  }
  return String(error);
}

