const fs = require("fs");
const path = require("path");
const Koa = require("koa");
const bodyParser = require("koa-bodyparser");
const bcrypt = require("bcrypt");
const request = require("supertest");

const requestId = require("../backend/src/middleware/request-id");
const errorHandler = require("../backend/src/middleware/error-handler");
const ApiError = require("../backend/src/errors/api-error");

const ROOT_DIR = path.resolve(__dirname, "..");
const SUMMARY_FILE = path.join(__dirname, ".summary");

function setModuleMock(modulePath, exportsObj) {
  require.cache[modulePath] = {
    id: modulePath,
    filename: modulePath,
    loaded: true,
    exports: exportsObj
  };
}

function clearModule(modulePath) {
  delete require.cache[modulePath];
}

function assert(condition, message, context = null) {
  if (!condition) {
    const error = new Error(message);
    error.context = context;
    throw error;
  }
}

function failureSnippet(error) {
  if (error.context) {
    return JSON.stringify(error.context).slice(0, 400);
  }
  if (error.stack) {
    return error.stack.split("\n").slice(0, 3).join(" | ");
  }
  return String(error);
}

async function withAuthApp(testFn) {
  const poolModulePath = require.resolve("../backend/src/db/pool");
  const loggerModulePath = require.resolve("../backend/src/logger");
  const auditModulePath = require.resolve("../backend/src/services/audit-log");
  const authRateLimitModulePath = require.resolve("../backend/src/middleware/auth-rate-limit");
  const authRoutesModulePath = require.resolve("../backend/src/modules/auth/auth.routes");

  const loggerMock = { info: () => {}, warn: () => {}, error: () => {} };
  const writeAuditEventMock = async () => {};

  const validPassword = "good-password-123";
  const validPasswordHash = bcrypt.hashSync(validPassword, 4);

  const connectionMock = {
    beginTransaction: async () => {},
    commit: async () => {},
    rollback: async () => {},
    release: () => {},
    query: async (sql) => {
      if (sql.includes("INSERT INTO auth_sessions")) return [{ insertId: 1001 }];
      if (sql.includes("UPDATE users SET last_login_at")) return [{ affectedRows: 1 }];
      if (sql.includes("SELECT r.code")) return [[{ code: "user" }]];
      if (sql.includes("SELECT id FROM device_fingerprints")) return [[]];
      if (sql.includes("INSERT INTO device_fingerprints")) return [{ insertId: 2001 }];
      if (sql.includes("INSERT INTO user_device_fingerprints")) return [{ affectedRows: 1 }];
      return [[]];
    }
  };

  const poolMock = {
    query: async (sql, params) => {
      if (sql.includes("FROM users") && sql.includes("WHERE username =")) {
        const username = String(params?.[0] || "");
        if (username === "valid-user") {
          return [[{ id: 10, username: "valid-user", email: "valid@example.local", password_hash: validPasswordHash, status: "active" }]];
        }
      }
      return [[]];
    },
    getConnection: async () => connectionMock
  };

  process.env.LOGIN_RATE_LIMIT_WINDOW_MS = "60000";
  process.env.LOGIN_RATE_LIMIT_MAX_PER_IP = "10";
  process.env.LOGIN_RATE_LIMIT_MAX_PER_IP_USERNAME = "3";

  clearModule(authRoutesModulePath);
  clearModule(authRateLimitModulePath);
  setModuleMock(poolModulePath, { pool: poolMock });
  setModuleMock(loggerModulePath, loggerMock);
  setModuleMock(auditModulePath, { writeAuditEvent: writeAuditEventMock });

  try {
    const app = new Koa();
    app.keys = ["api-test-secret"];
    app.proxy = true;
    app.use(errorHandler);
    app.use(requestId);
    app.use(bodyParser({ enableTypes: ["json"] }));

    const authRoutes = require("../backend/src/modules/auth/auth.routes");
    app.use(authRoutes.routes());
    app.use(authRoutes.allowedMethods());

    await testFn({ app, validPassword });
  } finally {
    clearModule(poolModulePath);
    clearModule(loggerModulePath);
    clearModule(auditModulePath);
    clearModule(authRateLimitModulePath);
    clearModule(authRoutesModulePath);
  }
}

async function withRefundsApp(requestRefundImpl, testFn) {
  const refundsServicePath = require.resolve("../backend/src/modules/payments/refunds.service");
  const paymentsRoutesPath = require.resolve("../backend/src/modules/payments/payments.routes");

  clearModule(paymentsRoutesPath);
  setModuleMock(refundsServicePath, { requestRefund: requestRefundImpl });

  try {
    const paymentsRoutes = require("../backend/src/modules/payments/payments.routes");
    const app = new Koa();
    app.use(errorHandler);
    app.use(requestId);
    app.use(bodyParser({ enableTypes: ["json"] }));
    app.use(async (ctx, next) => {
      const userId = ctx.get("x-test-user-id");
      if (userId) {
        ctx.state.user = {
          id: Number(userId),
          username: "api-test-user",
          email: "user@example.local",
          status: "active",
          roles: (ctx.get("x-test-user-roles") || "").split(",").map((x) => x.trim()).filter(Boolean)
        };
      }
      await next();
    });
    app.use(paymentsRoutes.routes());
    app.use(paymentsRoutes.allowedMethods());
    await testFn(app);
  } finally {
    clearModule(refundsServicePath);
    clearModule(paymentsRoutesPath);
  }
}

async function withFollowsApp(testFn) {
  const followsServicePath = require.resolve("../backend/src/modules/follows/follows.service");
  const followsRoutesPath = require.resolve("../backend/src/modules/follows/follows.routes");

  const followsByUser = new Map();
  const getSet = (id) => {
    if (!followsByUser.has(id)) followsByUser.set(id, new Set());
    return followsByUser.get(id);
  };

  const followsServiceMock = {
    listMyFollows: async (userId) => [...getSet(Number(userId))].map((targetId) => ({ user_id: targetId, username: `user-${targetId}` })),
    followUser: async ({ followerUserId, followedUserId }) => {
      const set = getSet(Number(followerUserId));
      const target = Number(followedUserId);
      const duplicate = set.has(target);
      set.add(target);
      return { followed: true, duplicate };
    },
    unfollowUser: async ({ followerUserId, followedUserId }) => {
      const set = getSet(Number(followerUserId));
      const target = Number(followedUserId);
      const removed = set.delete(target);
      return { followed: false, removed };
    }
  };

  clearModule(followsRoutesPath);
  setModuleMock(followsServicePath, followsServiceMock);

  try {
    const followsRoutes = require("../backend/src/modules/follows/follows.routes");
    const app = new Koa();
    app.use(errorHandler);
    app.use(requestId);
    app.use(bodyParser({ enableTypes: ["json"] }));
    app.use(async (ctx, next) => {
      const userId = ctx.get("x-test-user-id");
      if (userId) {
        ctx.state.user = { id: Number(userId), status: "active", roles: ["user"] };
      }
      await next();
    });
    app.use(followsRoutes.routes());
    app.use(followsRoutes.allowedMethods());
    await testFn(app);
  } finally {
    clearModule(followsServicePath);
    clearModule(followsRoutesPath);
  }
}

async function withStaffReviewsApp(testFn) {
  const reviewsServicePath = require.resolve("../backend/src/modules/reviews/reviews.service");
  const staffRoutesPath = require.resolve("../backend/src/modules/reviews/staff.routes");

  clearModule(staffRoutesPath);
  setModuleMock(reviewsServicePath, {
    listAppealsForStaff: async () => [{ id: 1, appeal_status: "submitted" }],
    addReply: async () => ({ id: 10 }),
