    app.use(async (ctx, next) => {
      const userId = ctx.get("x-test-user-id");
      if (userId) {
        ctx.state.user = {
          id: Number(userId),
          status: "active",
          roles: (ctx.get("x-test-user-roles") || "").split(",").map((x) => x.trim()).filter(Boolean)
        };
      }
      await next();
    });
    app.use(staffRoutes.routes());
    app.use(staffRoutes.allowedMethods());
    await testFn(app);
  } finally {
    clearModule(reviewsServicePath);
    clearModule(staffRoutesPath);
  }
}

async function withReviewsApp(testFn) {
  const reviewsServicePath = require.resolve("../backend/src/modules/reviews/reviews.service");
  const reviewsRoutesPath = require.resolve("../backend/src/modules/reviews/reviews.routes");

  clearModule(reviewsRoutesPath);
  setModuleMock(reviewsServicePath, {
    createReview: async () => {
      throw new ApiError(409, "REVIEW_ALREADY_EXISTS", "One primary review per order is allowed");
    },
    addFollowup: async () => ({}),
    listUserReviews: async () => [],
    getReviewDetail: async () => ({}),
    createAppeal: async () => ({}),
    uploadReviewImage: async () => ({}),
    getReviewImage: async () => ({ mime_type: "image/jpeg", file_path: __filename })
  });

  try {
    const reviewsRoutes = require("../backend/src/modules/reviews/reviews.routes");
    const app = new Koa();
    app.use(errorHandler);
    app.use(requestId);
