const tests = [
  {
    name: "auth_login_happy_path",
    module: "auth",
    run: async () => {
      await withAuthApp(async ({ app, validPassword }) => {
        const res = await request(app.callback()).post("/api/v1/auth/login").send({ username: "valid-user", password: validPassword });
        assert(res.status === 200, "expected 200", { status: res.status, body: res.body });
        assert(res.body?.data?.username === "valid-user", "expected returned username", res.body);
      });
    }
  },
  {
    name: "auth_login_missing_required_parameter",
    module: "auth",
    run: async () => {
      await withAuthApp(async ({ app }) => {
        const res = await request(app.callback()).post("/api/v1/auth/login").send({ username: "valid-user" });
        assert(res.status === 400, "expected 400 for missing parameter", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "auth_login_invalid_parameter_type",
    module: "auth",
    run: async () => {
      await withAuthApp(async ({ app }) => {
        const res = await request(app.callback()).post("/api/v1/auth/login").send({ username: 123, password: "x" });
        assert(res.status === 400, "expected 400 for invalid type", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "refunds_unauthorized_access",
    module: "payments",
    run: async () => {
      await withRefundsApp(async () => ({ id: 1 }), async (app) => {
        const res = await request(app.callback())
          .post("/api/v1/payments/orders/101/refunds")
          .send({ amountDollars: 1, reason: "test", idempotencyKey: "k1" });
        assert(res.status === 401, "expected 401 unauthorized", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "refunds_forbidden_for_non_privileged_role",
    module: "payments",
    run: async () => {
      await withRefundsApp(async () => ({ id: 1 }), async (app) => {
        const res = await request(app.callback())
          .post("/api/v1/payments/orders/101/refunds")
          .set("x-test-user-id", "11")
          .set("x-test-user-roles", "user")
          .send({ amountDollars: 1, reason: "test", idempotencyKey: "k2" });
        assert(res.status === 403, "expected 403 forbidden", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "refunds_happy_path_support_role",
    module: "payments",
    run: async () => {
      let called = 0;
      await withRefundsApp(async () => {
        called += 1;
        return { id: 77, refund_status: "processed", amount_cents: 100 };
      }, async (app) => {
        const res = await request(app.callback())
          .post("/api/v1/payments/orders/202/refunds")
          .set("x-test-user-id", "2")
          .set("x-test-user-roles", "support")
          .send({ amountDollars: 1, reason: "approved", idempotencyKey: "k3" });
        assert(res.status === 201, "expected 201 refund created", { status: res.status, body: res.body });
        assert(called === 1, "expected refund service called exactly once", { called });
      });
    }
  },
  {
    name: "refunds_not_found_propagates",
    module: "payments",
    run: async () => {
      await withRefundsApp(async () => {
        throw new ApiError(404, "ORDER_NOT_FOUND", "Order not found");
      }, async (app) => {
        const res = await request(app.callback())
          .post("/api/v1/payments/orders/999/refunds")
          .set("x-test-user-id", "2")
          .set("x-test-user-roles", "support")
          .send({ amountDollars: 1, reason: "approved", idempotencyKey: "k4" });
        assert(res.status === 404, "expected 404 not found", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "follows_state_change_pre_post_validation",
    module: "follows",
    run: async () => {
      await withFollowsApp(async (app) => {
        const pre = await request(app.callback()).get("/api/v1/follows/mine").set("x-test-user-id", "1");
        assert(Array.isArray(pre.body?.data) && pre.body.data.length === 0, "expected empty pre-state", pre.body);

        const follow = await request(app.callback()).post("/api/v1/follows/2").set("x-test-user-id", "1");
        assert(follow.status === 201, "expected follow create status", { status: follow.status, body: follow.body });

        const postFollow = await request(app.callback()).get("/api/v1/follows/mine").set("x-test-user-id", "1");
        assert(postFollow.body?.data?.length === 1, "expected one follow after mutation", postFollow.body);

        const unfollow = await request(app.callback()).delete("/api/v1/follows/2").set("x-test-user-id", "1");
        assert(unfollow.status === 200, "expected unfollow success", { status: unfollow.status, body: unfollow.body });

        const postUnfollow = await request(app.callback()).get("/api/v1/follows/mine").set("x-test-user-id", "1");
        assert(postUnfollow.body?.data?.length === 0, "expected empty post-state", postUnfollow.body);
      });
    }
  },
  {
    name: "follows_invalid_parameter_format",
    module: "follows",
    run: async () => {
      await withFollowsApp(async (app) => {
        const res = await request(app.callback()).post("/api/v1/follows/not-a-number").set("x-test-user-id", "1");
        assert(res.status === 400, "expected 400 for invalid userId parameter", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "staff_appeals_unauthorized",
    module: "staff_reviews",
    run: async () => {
      await withStaffReviewsApp(async (app) => {
        const res = await request(app.callback()).get("/api/v1/staff/reviews/appeals");
        assert(res.status === 401, "expected 401 unauthorized", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "staff_appeals_forbidden_for_user_role",
    module: "staff_reviews",
    run: async () => {
      await withStaffReviewsApp(async (app) => {
        const res = await request(app.callback())
          .get("/api/v1/staff/reviews/appeals")
          .set("x-test-user-id", "14")
          .set("x-test-user-roles", "user");
        assert(res.status === 403, "expected 403 forbidden", { status: res.status, body: res.body });
      });
    }
  },
  {
    name: "staff_appeals_happy_path_support",
    module: "staff_reviews",
    run: async () => {
      await withStaffReviewsApp(async (app) => {
        const res = await request(app.callback())
          .get("/api/v1/staff/reviews/appeals")
          .set("x-test-user-id", "15")
          .set("x-test-user-roles", "support");
        assert(res.status === 200, "expected 200 for support role", { status: res.status, body: res.body });
        assert(Array.isArray(res.body?.data), "expected appeals list", res.body);
      });
    }
  },
  {
    name: "reviews_create_conflict_409",
    module: "reviews",
    run: async () => {
      await withReviewsApp(async (app) => {
        const res = await request(app.callback())
          .post("/api/v1/reviews")
          .set("x-test-user-id", "7")
          .send({ orderId: 1, rating: 5, reviewText: "Great service", anonymousDisplay: false, dimensionScores: [] });
        assert(res.status === 409, "expected 409 conflict", { status: res.status, body: res.body });
        assert(res.body?.error?.code === "REVIEW_ALREADY_EXISTS", "expected review conflict code", res.body);
      });
    }
  }
];

async function main() {
  let passed = 0;
  let failed = 0;

  console.log("API FUNCTIONAL TESTS");
  for (const test of tests) {
    try {
      await test.run();
      passed += 1;
      console.log(`[PASS] ${test.name}`);
    } catch (error) {
      failed += 1;
      console.log(`[FAIL] ${test.name}`);
      console.log(`  reason: ${error.message}`);
      console.log(`  log: ${failureSnippet(error)}`);
    }
  }

  const todoGaps = [
    "TODO_GAP: dedicated hiring module endpoints are not present in this repository",
    "TODO_GAP: dedicated inventory module endpoints are not present in this repository",
    "TODO_GAP: compliance module is represented via reviews governance routes only; standalone compliance API not found"
  ];

  console.log("");
  console.log("API TEST SUMMARY");
  console.log(`TOTAL=${tests.length}`);
  console.log(`PASSED=${passed}`);
  console.log(`FAILED=${failed}`);
  for (const gap of todoGaps) {
    console.log(gap);
  }

  fs.writeFileSync(SUMMARY_FILE, `TOTAL=${tests.length}\nPASSED=${passed}\nFAILED=${failed}\n`, "utf8");
  process.exit(failed > 0 ? 1 : 0);
}

main().catch((error) => {
  console.log("[FAIL] api_runner_fatal_error");
  console.log(`  reason: ${error.message}`);
  console.log(`  log: ${failureSnippet(error)}`);
  fs.writeFileSync(SUMMARY_FILE, "TOTAL=1\nPASSED=0\nFAILED=1\n", "utf8");
  process.exit(1);
});

