  const authRoutesModulePath = require.resolve("../backend/src/modules/auth/auth.routes");

  const loggerMock = { info: () => {}, warn: () => {}, error: () => {} };
  const writeAuditEventMock = async () => {};

  const validPassword = "good-password-123";
  const validPasswordHash = bcrypt.hashSync(validPassword, 4);

  const connectionMock = {
    beginTransaction: async () => {},
    commit: async () => {},
    rollback: async () => {},
    release: () => {},
    query: async (sql) => {
      if (sql.includes("INSERT INTO auth_sessions")) return [{ insertId: 1001 }];
      if (sql.includes("UPDATE users SET last_login_at")) return [{ affectedRows: 1 }];
      if (sql.includes("SELECT r.code")) return [[{ code: "user" }]];
      if (sql.includes("SELECT id FROM device_fingerprints")) return [[]];
      if (sql.includes("INSERT INTO device_fingerprints")) return [{ insertId: 2001 }];
      if (sql.includes("INSERT INTO user_device_fingerprints")) return [{ affectedRows: 1 }];
      return [[]];
    }
  };

  const poolMock = {
    query: async (sql, params) => {
      if (sql.includes("FROM users") && sql.includes("WHERE username =")) {
        const username = String(params?.[0] || "");
        if (username === "valid-user") {
          return [[{ id: 10, username: "valid-user", email: "valid@example.local", password_hash: validPasswordHash, status: "active" }]];
        }
      }
      return [[]];
    },
    getConnection: async () => connectionMock
  };

  process.env.LOGIN_RATE_LIMIT_WINDOW_MS = "60000";
  process.env.LOGIN_RATE_LIMIT_MAX_PER_IP = "10";
  process.env.LOGIN_RATE_LIMIT_MAX_PER_IP_USERNAME = "3";

  clearModule(authRoutesModulePath);
  clearModule(authRateLimitModulePath);
  setModuleMock(poolModulePath, { pool: poolMock });
  setModuleMock(loggerModulePath, loggerMock);
  setModuleMock(auditModulePath, { writeAuditEvent: writeAuditEventMock });

  try {
    const app = new Koa();
    app.keys = ["api-test-secret"];
    app.proxy = true;
    app.use(errorHandler);
    app.use(requestId);
    app.use(bodyParser({ enableTypes: ["json"] }));

    const authRoutes = require("../backend/src/modules/auth/auth.routes");
    app.use(authRoutes.routes());
    app.use(authRoutes.allowedMethods());

    await testFn({ app, validPassword });
  } finally {
    clearModule(poolModulePath);
    clearModule(loggerModulePath);
    clearModule(auditModulePath);
    clearModule(authRateLimitModulePath);
    clearModule(authRoutesModulePath);
  }
}

