    if (!followsByUser.has(id)) followsByUser.set(id, new Set());
    return followsByUser.get(id);
  };

  const followsServiceMock = {
    listMyFollows: async (userId) => [...getSet(Number(userId))].map((targetId) => ({ user_id: targetId, username: `user-${targetId}` })),
    followUser: async ({ followerUserId, followedUserId }) => {
      const set = getSet(Number(followerUserId));
      const target = Number(followedUserId);
      const duplicate = set.has(target);
      set.add(target);
      return { followed: true, duplicate };
    },
    unfollowUser: async ({ followerUserId, followedUserId }) => {
      const set = getSet(Number(followerUserId));
